module RefModule(
    input  wire        CLK,
    input  wire        RST,
    input  wire        EN,
    output wire [3:0]  Q
);reg [3:0] obf_count;

    always @(posedge CLK) begin
        if (RST) begin
            obf_count <= 4'b0;
        end
        else if (EN) begin
            obf_count <= obf_count + 1;
        end
    end

    assign Q = obf_count;

endmodule
